    assert(inode_num > 0);
    printf("  ✓ Created /testfile.txt (inode %lu)\n", inode_num);
    const char* test_data = "Hello, Filesystem World!";
    size_t data_len = strlen(test_data);
    ssize_t written = fs_write(fs, inode_num, 0, test_data, data_len);
